   Examples:
   input: [7, 9, 5, 2, 8, 16, 4, 1]
   output: 1
   input: [8, 36, 7, 2, 11]
   output: 7
*/
int smallestOdd(const std::vector<int> &x) {
    const int INF = std::numeric_limits<int>::max();
    int global_min = INF;

    #pragma omp parallel
    {
        int local_min = INF;

        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            int val = x[i];
            if ((val & 1) && val < local_min) {
                local_min = val;
            }
        }

        #pragma omp critical
        if (local_min < global_min) {
            global_min = local_min;
        }
    }

    return global_min;
}
