inline void countQuadrants(const std::vector<Point>& points, std::array<size_t,4>& bins)
{
    // Initialize all bins to zero
    bins.fill(0);

    /* Work in parallel. Each thread keeps a private local array
       which will be reduced after the loop.  The reduction is
       performed with a critical section to avoid multiple
       conflicting updates to the shared array. */
    #pragma omp parallel
    {
        // Private accumulators for each thread
        size_t local[4] = {0,0,0,0};

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i)
        {
            const double& x = points[i].x;
            const double& y = points[i].y;

            // Branchless quadrant test
            if (x >= 0.0) {
                if (y >= 0.0) {
                    ++local[0];
                } else {
                    ++local[3];
                }
            } else {
                if (y >= 0.0) {
                    ++local[1];
                } else {
                    ++local[2];
                }
            }
        }

        // Combine local results into the global bins
        #pragma omp critical
        {
            for (int q = 0; q < 4; ++q)
                bins[q] += local[q];
        }
    }
}
