/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
bool reduceLogicalXOR(const std::vector<bool>& x)
{
    // XOR over the entire vector is equivalent to the parity of the number of
    // set bits.  A parallel reduction is used to keep the runtime low on
    // multi‑core CPUs while still preserving the exact logical behaviour.
    bool parity = false;

    // Parallel loop with xor reduction.  The loop bounds are split
    // into chunks for the OpenMP runtime.  Running a single pass is
    // sufficiently fast for most workloads, but the reduction
    // terminates the same way as a sequential XOR.
    #pragma omp parallel for reduction(^ : parity)
    for (std::size_t i = 0; i < x.size(); ++i)
        parity ^= x[i];

    return parity;
}
