/* Return the sum of the minimum value at each index of vectors x and y for all indices.
   i.e. sum = min(x_0, y_0) + min(x_1, y_1) + min(x_2, y_2) + ...
   Example:
   input: x=[3, 4, 0, 2, 3], y=[2, 5, 3, 1, 7]
   output: 10
*/
inline int64_t sumOfMinimumElements(const std::vector<int64_t>& x, const std::vector<int64_t>& y)
{
    const std::size_t n = x.size();
    // If the sizes might differ, only process the common prefix to preserve behaviour
    const std::size_t m = std::min(n, y.size());

    int64_t sum = 0;
#pragma omp parallel for reduction(+:sum) schedule(static)
    for (std::size_t i = 0; i < m; ++i)
    {
        const int64_t a = x[i];
        const int64_t b = y[i];
        sum += (a < b ? a : b);
    }

    // Handle any remaining elements if the vectors are of different sizes.
    // The original code assumed equal sizes, but for safety we include this.
    for (std::size_t i = m; i < n; ++i)
        sum += x[i];
    for (std::size_t i = m; i < y.size(); ++i)
        sum += y[i];

    return sum;
}
