#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

/*
 * Compute element‑wise ReLU on the input vector `x`.
 * This implementation preserves the exact specification of the
 * original function while exploiting SIMD vectorisation and OpenMP
 * parallelism for maximum speed on an 8‑core x86‑64 machine.
 *
 * The function is in‑place: the input vector `x` is overwritten with
 * the result.  It works for any size of vector (even zero).
 */
inline void relu(std::vector<double> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* Try to use an aligned loop for better cache utilisation */
    const std::size_t stride = 16;          // 16 doubles = 128 bytes (cache line)
    const std::size_t up_to = N / stride * stride;

#pragma omp parallel for schedule(static, 64)
    for (std::size_t i = 0; i < up_to; i += stride)
    {
        /* Process 16 elements at a time using manual unrolling.
         * This avoids the overhead of the std::transform call and
         * allows the compiler to emit efficient SIMD instructions. */
        for (std::size_t j = 0; j < stride; ++j)
        {
            double v = x[i + j];
            x[i + j] = (v > 0.0) ? v : 0.0;
        }
    }

    /* Handle the remaining elements (if N is not a multiple of 16) */
    for (std::size_t i = up_to; i < N; ++i)
        x[i] = (x[i] > 0.0) ? x[i] : 0.0;
}
