/*
 * Compute the highest node degree in the undirected graph.
 * The graph is defined in the adjacency matrix A (row‑major).
 * A is an NxN adjacency matrix stored as a flat std::vector<int> of length N * N.
 * The function returns the maximum degree (number of 1s in any row).
 *
 * Parameters
 * ---------
 * A : const std::vector<int>&
 *     The adjacency matrix flattened in row major order.
 * N : size_t
 *     The dimension of the matrix (number of vertices).
 *
 * Returns
 * -------
 * int
 *     The maximum node degree.
 *
 * This implementation uses OpenMP to parallelise the outer loop
 * and a pointer based inner loop for maximum cache locality.
 * The behaviour is bit‑for‑bit identical to the original code.
 */
int maxDegree(const std::vector<int> &A, size_t N) noexcept {
    int highestDegree = 0;
    const int *data = A.data();

    /* Parallelise rows with a reduction on highestDegree. */
    #pragma omp parallel for schedule(static) reduction(max : highestDegree)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int *row = data + i * static_cast<int>(N);
        int degree = 0;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            // `A` contains only 0/1 values, so a simple integer addition is fine.
            degree += row[j];
        }
        if (degree > highestDegree) highestDegree = degree;
    }
    return highestDegree;
}
