```cpp
#pragma once
#include <vector>
#include <limits>
#include <algorithm>

/* Return the length of the shortest path from source to dest
   in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major order.
   The function keeps exactly the same semantics as the original.
 */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Use an array for visited / distance together for cache friendliness.
    std::vector<int> dist(N, -1);          // -1 denotes 'unvisited'
    std::vector<int> queue;                // simple queue implemented with two indices
    queue.reserve(N);
    dist[source] = 0;
    queue.push_back(source);

    size_t head = 0;
    while (head < queue.size()) {
        int cur = queue[head++];
        int curDist = dist[cur];
        if (cur == dest)
            return curDist;

        // Scan all neighbours
        size_t base = static_cast<size_t>(cur) * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[base + i] && dist[i] == -1) { // unvisited neighbour
                dist[i] = curDist + 1;
                queue.push_back(static_cast<int>(i));
            }
        }
    }
    return std::numeric_limits<int>::max(); // unreachable (should not happen)
}
