#pragma once
#include <vector>
#include <cstdint>
#include <cstring>
#include <algorithm>

/* Helper: iterative DFS using an explicit stack.
   The adjacency matrix A is a flattened NxN matrix stored in row‑major order.
   The visited array is a byte array (uint8_t) where 0=unvisited, 1=visited. */
static void dfs_iterative(const std::vector<int> &A, size_t N,
                          uint8_t *visited, size_t start, int &componentSize)
{
    static std::vector<size_t> stack;
    stack.clear();
    stack.push_back(start);
    visited[start] = 1;
    componentSize = 0;

    const int *rowStart = A.data();

    while (!stack.empty()) {
        size_t node = stack.back();
        stack.pop_back();

        ++componentSize;

        const int *row = rowStart + node * N;
        for (size_t nb = 0; nb < N; ++nb) {
            if (row[nb] && !visited[nb]) {
                visited[nb] = 1;
                stack.push_back(nb);
            }
        }
    }
}

/* Return the number of vertices in the largest component of the graph
   defined by the adjacency matrix A, which is a flattened NxN matrix. */
int largestComponent(const std::vector<int> &A, size_t N)
{
    // use a byte per vertex instead of std::vector<bool>
    std::vector<uint8_t> visited(N);
    std::memset(visited.data(), 0, N);

    int maxCount = 0;
    for (size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            int count = 0;
            dfs_iterative(A, N, visited.data(), i, count);
            if (count > maxCount) maxCount = count;
        }
    }
    return maxCount;
}
