struct COOElement {
   size_t row, column;
   double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
void spmv(double alpha,
          std::vector<COOElement> const& A,
          std::vector<double> const& x,
          double beta,
          std::vector<double> & y,
          size_t M,
          size_t N)
{
    // Scale the output vector by beta.
    // Parallel scaling – every element is independent.
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(y.size()); ++i) {
        y[static_cast<size_t>(i)] *= beta;
    }

    // Accumulate contributions from the COO representation.
    // Each thread processes a chunk of COO entries; atomic updates
    // guarantee correct results when multiple entries target the same row.
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t ai = 0; ai < static_cast<ptrdiff_t>(A.size()); ++ai) {
        const COOElement &e = A[static_cast<size_t>(ai)];
        if (e.row < M && e.column < N) {
            double tmp = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += tmp;
        }
    }
}
