#include <cstdlib>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Optimised sparse‑sparse matrix multiplication.
 *   Y = A * X
 *   A : M x K sparse matrix in COO format
 *   X : K x N sparse matrix in COO format
 *   Y : M x N dense matrix in row-major storage
 *
 * Expected behaviour is identical to the reference implementation.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    // ----------------------------------------------------------------------
    // 1. Build an index of X elements grouped by their row (i.e. by the
    //    column index of A that will match them).
    // ----------------------------------------------------------------------
    std::vector<std::vector<COOElement>> XbyRow(K);
    for (auto const& xe : X) {
        // No bound checking is required – the kernel guarantees
        // that 0 <= xe.row < K.
        XbyRow[xe.row].push_back(xe);
    }

    // ----------------------------------------------------------------------
    // 2. Prepare the dense result matrix.
    // ----------------------------------------------------------------------
    Y.assign(M * N, 0.0);

    // ----------------------------------------------------------------------
    // 3. Parallel loop over all elements of A.
    // ----------------------------------------------------------------------
    #pragma omp parallel for schedule(dynamic, 64)
    for (size_t i = 0; i < A.size(); ++i) {
        const COOElement& a = A[i];
        // For this row, only X elements whose row == a.column can
        // contribute to the dot‑product.
        const auto& matchingX = XbyRow[a.column];
        size_t base = a.row * N;                 // starting offset in Y
        double a_val = a.value;

        for (auto const& xe : matchingX) {
            Y[base + xe.column] += a_val * xe.value;
        }
    }
}
