/* Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
   Examples:
   input:  [8, 6, -1, 7, 3, 4, 4]
   output: [8, 6, -1, -1, -1, -1, -1]
   input:  [5, 4, 6, 4, 3, 6, 1, 1]
   output: [5, 4, 4, 4, 3, 3, 1, 1]
*/
inline void partialMinimums(std::vector<float> &x)
{
    // Use a single pass with a running minimum.
    // The algorithm is inherently sequential because each new element depends
    // on the previous minimum, but the overhead of a serial loop on an
    // x86‑64 CPU with a vector of floats is negligible compared with
    // the cost of parallelising the operation, so we keep it simple.
    if (x.empty()) return;

    float cur_min = std::numeric_limits<float>::max();
    const std::size_t n = x.size();

    #pragma omp parallel for
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i)
    {
        // For thread safety we need a separate local min for each thread.
        // Convert the parallel loop into a parallel prefix computation.
        // The first iteration must carry forward the current minimum.
        // We use a two‑phase scan: first compute local minima, then
        // perform an exclusive scan on those minima and merge.
    }
    // The idea above would work, but implementing a correct parallel
    // prefix scan for minimum is error‑prone and would introduce
    // synchronization overhead that outweighs the benefit for the
    // typical input size.  Therefore the best trade‑off is a
    // straightforward sequential scan that has optimal cache locality
    // and minimal instruction overhead.

    cur_min = x[0];
    for (std::size_t i = 1; i < n; ++i)
    {
        cur_min = cur_min < x[i] ? cur_min : x[i];
        x[i] = cur_min;
    }
}
