#pragma once
#include <vector>

struct COOElement {
    size_t row, column;
    double value;
};

/* Factorize the sparse matrix A into A = LU where L is lower triangular (unit diagonal)
   and U is upper triangular. The matrix A is given in COO form. L and U are returned
   as flat row‑major arrays of size N * N. */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N) {
    // Build a dense N×N representation of A in row‑major order
    std::vector<double> denseA(N * N, 0.0);
    for (const auto& e : A) {
        denseA[e.row * N + e.column] = e.value;
    }

    // Resize output containers
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    // Perform Doolittle LU factorisation without pivoting
    for (size_t i = 0; i < N; ++i) {
        // Compute row i of U
        for (size_t j = i; j < N; ++j) {
            double sum = denseA[i * N + j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        // Compute column i of L (excluding diagonal)
        for (size_t j = i + 1; j < N; ++j) {
            double sum = denseA[j * N + i];
            for (size_t k = 0; k < i; ++k)
                sum -= L[j * N + k] * U[k * N + i];
            L[j * N + i] = sum / U[i * N + i];
        }

        // Unit diagonal of L
        L[i * N + i] = 1.0;
    }
}
