// Compute the discrete Fourier transform of a real‑valued sequence x.
// The result is written to the vector `output`.  The function is fully
// equivalent to the reference implementation, but internally it uses
// a multiplier‑recurrence to avoid expensive trigonometric calls
// and it parallelises the outer loop with OpenMP.
inline void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.resize(N, {0.0, 0.0});

    // Pre‑compute the primitive N‑th roots of unity: W_k = exp(-2πi k / N)
    std::vector<std::complex<double>> w(N);
    const double two_pi_over_N = -2.0 * M_PI / static_cast<double>(N);
    for (std::size_t k = 0; k < N; ++k) {
        double angle = two_pi_over_N * static_cast<double>(k);
        w[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // Parallelise the outer loop – each output coefficient can be computed independently.
    #pragma omp parallel for schedule(static)
    for (int k_int = 0; k_int < static_cast<int>(N); ++k_int) {
        std::size_t k = static_cast<std::size_t>(k_int);
        std::complex<double> sum(0.0, 0.0);
        std::complex<double> c(1.0, 0.0);          // exp(0) = 1
        const std::complex<double>& wk = w[k];    // exp(-2πi k / N)

        // Accumulate the dot product using the recurrence c *= wk
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * c;
            c *= wk;   // advance by one step
        }
        output[k] = sum;
    }
}
