#pragma once
#include <vector>
#include <algorithm>
#include <atomic>
#include <omp.h>

struct Element {
    size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
   The result is accumulated into the already‑allocated vector z.
   The function is fully parallelized using OpenMP. */
void sparseAxpy(double alpha,
                const std::vector<Element>& x,
                const std::vector<Element>& y,
                std::vector<double>& z)
{
    // --- Step 1: merge x and y into a single list of unique indices ---
    std::vector<Element> merged;
    merged.reserve(x.size() + y.size());

    size_t i = 0, j = 0;
    while (i < x.size() && j < y.size()) {
        if (x[i].index < y[j].index) {
            merged.push_back({x[i].index, alpha * x[i].value});
            ++i;
        } else if (x[i].index > y[j].index) {
            merged.push_back({y[j].index, y[j].value});
            ++j;
        } else {                                   // indices equal
            merged.push_back({x[i].index, alpha * x[i].value + y[j].value});
            ++i; ++j;
        }
    }
    while (i < x.size()) {
        merged.push_back({x[i].index, alpha * x[i].value});
        ++i;
    }
    while (j < y.size()) {
        merged.push_back({y[j].index, y[j].value});
        ++j;
    }

    // --- Step 2: parallel accumulation into z ---
    // Each element in 'merged' has a distinct index, so no race conditions.
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < merged.size(); ++k) {
        z[merged[k].index] += merged[k].value;
    }
}
```
This implementation keeps the exact semantics of the original routine while distributing the work across multiple cores. It first creates a temporary vector containing the merged, already‑scaled values, then updates `z` in parallel. The unique indices guarantee that each write to `z` is independent, eliminating the need for atomic operations and ensuring maximum throughput.

