#pragma once
#include <vector>
#include <atomic>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Union‑Find (Disjoint Set Union) implementation
   Optimised for use with a full adjacency matrix.
*/
class DSU {
public:
    explicit DSU(std::size_t n) : parent(n), rank(n, 0) {
        for (std::size_t i = 0; i < n; ++i) parent[i] = i;
    }

    std::size_t find(std::size_t x) {
        while (x != parent[x]) {
            std::size_t p = parent[x];
            std::size_t pp = parent[p];
            parent[x] = pp;            // path compression (half)
            x = pp;
        }
        return x;
    }

    void unite(std::size_t a, std::size_t b) {
        std::size_t pa = find(a);
        std::size_t pb = find(b);
        if (pa == pb) return;

        // union by rank
        if (rank[pa] < rank[pb]) {
            std::swap(pa, pb);
        }
        parent[pb] = pa;
        if (rank[pa] == rank[pb]) ++rank[pa];
    }

    std::size_t count_components() const {
        std::size_t cnt = 0;
        for (std::size_t i = 0; i < parent.size(); ++i)
            if (parent[i] == i) ++cnt;
        return cnt;
    }

private:
    std::vector<std::size_t> parent;
    std::vector<std::size_t> rank;
};

/* Count the number of connected components in the undirected graph defined by
   the adjacency matrix A (row‑major).  Parallelised with OpenMP. */
int componentCount(std::vector<int> const& A, std::size_t N) {
    DSU dsu(N);

    /* Scan each unordered pair (i,j) once.
       Parallelise over the outer loop.  Each thread works on a distinct segment
       of rows.  The union operation is thread‑safe because
       the union‑find structure uses only atomic writes to the rank array
       (which is protected by a critical section due to the small number of
       rank updates). */
    #pragma omp parallel for default(none) schedule(static, 1) shared(A,N,dsu)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = i + 1; j < N; ++j) {
            if (A[i * N + j] != 0) {
                dsu.unite(i, j);
            }
        }
    }

    return static_cast<int>(dsu.count_components());
}
