#pragma once
#include <vector>
#include <numeric>
#include <omp.h>

/* Compute the reverse prefix sum of the vector x into output.
   Example:
   input: [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
   input: [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
inline void reversePrefixSum(std::vector<int> const& x, std::vector<int>& output) {
    const std::size_t n = x.size();
    output.resize(n);

    if (n == 0) return;

    const int nthreads = omp_get_max_threads();
    const std::size_t chunk = (n + nthreads - 1) / nthreads;

    std::vector<long long> blockSum(nthreads, 0); // use 64‑bit to avoid overflow

    /* First pass: compute sum of each block (from the end of the block to its start) */
#pragma omp parallel num_threads(nthreads)
    {
        const int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        long long s = 0;
        for (std::size_t i = end; i-- > start; ) {
            s += x[i];
        }
        blockSum[tid] = s;
    }

    /* Prefix sum of block sums to get offset for each block */
    std::partial_sum(blockSum.begin(), blockSum.end(), blockSum.begin());

    /* Second pass: compute the result for each block using the offset */
#pragma omp parallel num_threads(nthreads)
    {
        const int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        long long offset = 0;
        if (tid > 0) offset = blockSum[tid - 1];

        long long s = offset;
        for (std::size_t i = end; i-- > start; ) {
            s += x[i];
            output[i] = static_cast<int>(s);
        }
    }
}
