/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
static inline double closestPair(std::vector<double> const& x)
{
    // The vector needs to have at least two elements
    if (x.size() < 2)
        return 0.0;

    /* 1. Make a copy that can be sorted in place.  */
    std::vector<double> v(x.begin(), x.end());

    /* 2. Sort the copy.  The standard library can accept an
       execution policy since C++17; GCC already supplies
       parallel execution via OpenMP.  We manually synchronize
       to avoid pulling in extra headers.  */
#pragma omp parallel shared(v)
    {
#pragma omp single nowait
        std::sort(v.begin(), v.end());
    }

    /* 3. Find the minimum adjacent difference using parallel reduction.
       Adjacent pairs are independent, so we can divide the work across
       threads without data races.  */
    double local_min = std::numeric_limits<double>::max();

    #pragma omp parallel for schedule(static) reduction(min : local_min)
    for (size_t i = 0; i + 1 < v.size(); ++i)
    {
        double d = std::fabs(v[i+1] - v[i]);
        if (d < local_min) local_min = d;
    }

    return local_min;
}
