```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Exact‑behaviour solver for Ax=b with A in COO format.
   The implementation keeps the same algorithmic logic (Gaussian
   elimination with partial pivoting) but exploits OpenMP to
   parallelise the independent parts. */
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    /* --- 1. Build a dense matrix ----------------------------------- */
    std::vector<std::vector<double>> matrix(N, std::vector<double>(N, 0.0));
    for (const auto& e : A)
        matrix[e.row][e.column] = e.value;                     // O(|A|)

    /* --- 2. Copy source vector ------------------------------------- */
    std::vector<double> b_copy(b);                              // O(N)

    /* --- 3. Gaussian elimination with partial pivoting ------------- */
    for (size_t i = 0; i < N; ++i) {
        /* ---- 3a. Find pivot row (maximum in column i) ------------- */
        double maxAbs = std::abs(matrix[i][i]);
        size_t maxRow = i;
        #pragma omp parallel for reduction(max:maxAbs)
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k][i]);
            if (val > maxAbs) {
                maxAbs = val;
                #pragma omp critical
                    maxRow = k;
            }
        }

        /* ---- 3b. Swap pivot row with current row ----------------- */
        if (maxRow != i) {
            std::swap_ranges(matrix[i].begin() + i, matrix[i].end(),
                             matrix[maxRow].begin() + i);
            std::swap(b_copy[i], b_copy[maxRow]);
        }

        /* ---- 3c. Eliminate rows below (parallel) ------------------ */
        double pivot = matrix[i][i];
        #pragma omp parallel for
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -matrix[k][i] / pivot;
            for (size_t j = i; j < N; ++j) {
                if (j == i)
                    matrix[k][j] = 0.0;          // explicit zero
                else
                    matrix[k][j] += factor * matrix[i][j];
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    /* --- 4. Back substitution ------------------------------------- */
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / matrix[i][i];
        for (int k = i - 1; k >= 0; --k)
            b_copy[k] -= matrix[k][i] * x[i];
    }
}
