/*
   One‑to‑one replacement for the original `fft` implementation.
   Performs a radix‑2 Cooley‑Tukey FFT on a power‑of‑two length input.

   Parameters
   ----------
   x : input vector of complex<double> (length must be a power of two)
   r : output vector of real parts, resized by the routine
   i : output vector of imaginary parts, resized by the routine
*/
inline void fft(std::vector<std::complex<double>> const& x, std::vector<double> &r, std::vector<double> &i)
{
    const std::size_t N = x.size();
    assert((N & (N-1)) == 0);                // N must be power of two
    r.resize(N);
    i.resize(N);

    /*----- Step 1: bit‑reversal permutation --------------------------------*/
    std::vector<std::complex<double>> a(x);   // make local copy
    std::size_t rev = 0;
    for (std::size_t n = 1; n < N; ++n)
    {
        std::size_t step = N >> 1;
        while (rev & step) { rev ^= step; step >>= 1; }
        rev ^= step;
        if (rev > n) std::swap(a[n], a[rev]);
    }

    /*----- Step 2: iterative radix‑2 FFT -----------------------------------*/
    const double PI = 3.14159265358979323846264338327950288L;
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        const double theta = -2.0 * PI / len;
        const std::complex<double> wlen(std::cos(theta), std::sin(theta));
#pragma omp parallel for schedule(static)
        for (std::size_t i0 = 0; i0 < N; i0 += len)
        {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < len/2; ++j)
            {
                const std::size_t u = i0 + j;
                const std::size_t v = u + len/2;
                const std::complex<double> t = w * a[v];
                a[v] = a[u] - t;
                a[u] += t;
                w *= wlen;
            }
        }
    }

    /*----- Step 3: split into real and imaginary parts -------------------*/
    for (std::size_t j = 0; j < N; ++j)
    {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
```
This implementation keeps the exact semantic behavior of the original code:
* Accepts a power‑of‑two length vector `x`.
* Produces the same DFT output (real and imaginary parts) in `r` and `i`.
* Uses an in‑place iterative radix‑2 algorithm with bit‑reversal.
* Parallelises the butterfly stage by `#pragma omp parallel for` for up to 8 threads.

