#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/**
 * Computes the FFT of `x` and stores the result in `output`.
 * Behaviour is identical to the reference implementation.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    constexpr size_t log2_32 = 5; // for 32‑bit mask shift
    size_t N = x.size();
    output = x;                     // start with a copy

    // ----- Cooley–Tukey iterative FFT -----
    size_t k = N, n;
    const double theta = M_PI / N;
    std::complex<double> w_m(std::cos(theta), -std::sin(theta)), w;
    while (k > 1)
    {
        n = k;
        k >>= 1;
        w_m = w_m * w_m;               // (w_m)^2
        w = 1.0;

        for (size_t l = 0; l < k; ++l)
        {
            for (size_t a = l; a < N; a += n)
            {
                size_t b = a + k;
                std::complex<double> t = output[a] - output[b];
                output[a] += output[b];
                output[b] = t * w;
            }
            w *= w_m;
        }
    }

    // ----- Bit‑reversal permutation -----
    const size_t m = static_cast<size_t>(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (size_t a = 0; a < N; ++a)
    {
        size_t b = a;
        // 32‑bit reverse then shift right by (32-m)
        b = (((b & 0xaaaaaaaa) >> 1) | ((b & 0x55555555) << 1));
        b = (((b & 0xcccccccc) >> 2) | ((b & 0x33333333) << 2));
        b = (((b & 0xf0f0f0f0) >> 4) | ((b & 0x0f0f0f0f) << 4));
        b = (((b & 0xff00ff00) >> 8) | ((b & 0x00ff00ff) << 8));
        b = ((b >> 16) | (b << 16)) >> (32 - m);

        if (b > a)
            std::swap(output[a], output[b]);
    }
}
