```cpp
#pragma once
#include <vector>
#include <omp.h>

/* Factorize the matrix A into A = LU (in-place, row‑major)
   L is stored in the lower part (below the diagonal) with unit diagonal,
   U is stored in the upper part (including the diagonal).
   The algorithm is the classical Doolittle LU without pivoting.
   Function preserves exact numerical results (up to normal floating‑point
   rounding) of the sequential implementation.
*/
void luFactorize(std::vector<double> &A, size_t N) {
#pragma omp parallel for schedule(dynamic, 64) collapse(1)
    for (size_t k = 0; k < N; ++k) {
        // pivot element
        double Akk = A[k * N + k];
        // Avoid division by zero – user guarantees matrix is non‑singular
        for (size_t i = k + 1; i < N; ++i) {
            double factor = A[i * N + k] / Akk;
            A[i * N + k] = factor;                    // store L element
            // Update the remaining row
            const double *rowK = &A[k * N];
            double *rowI = &A[i * N];
            for (size_t j = k + 1; j < N; ++j) {
                rowI[j] -= factor * rowK[j];
            }
        }
    }
}
