/*
 * Compute the prefix sum array of the vector `x` and return its sum.
 * Example:
 *   input: [-7, 2, 1, 9, 4, 8]
 *   output: 15
 */
inline int64_t sumOfPrefixSum(const std::vector<int64_t> &x) {
    const size_t n = x.size();
    if (n == 0) return 0;

    std::vector<int64_t> prefix(n);

    const int num_threads = omp_get_max_threads();
    std::vector<int64_t> thread_sums(num_threads, 0);

    // Parallel inclusive prefix scan (block scan)
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t chunk = (n + num_threads - 1) / num_threads;
        const size_t start = tid * chunk;
        size_t end = start + chunk;
        if (end > n) end = n;
        if (start >= end) return;

        // 1. Local inclusive scan
        int64_t local_sum = 0;
        for (size_t i = start; i < end; ++i) {
            local_sum += x[i];
            prefix[i] = local_sum;
        }
        thread_sums[tid] = local_sum;

        // 2. Prefix sum of thread sums to get block offsets
#pragma omp barrier
        int64_t offset = 0;
        for (int j = 0; j < tid; ++j) offset += thread_sums[j];

        // 3. Add offset to each element in the block
        for (size_t i = start; i < end; ++i) {
            prefix[i] += offset;
        }
    }

    // Parallel reduction to sum all prefix elements
    int64_t total_sum = 0;
#pragma omp parallel for reduction(+:total_sum)
    for (size_t i = 0; i < n; ++i) {
        total_sum += prefix[i];
    }

    return total_sum;
}
