/*
 * For each cell in an N×N grid, count the number of orthogonal neighbours equal to 1.
 * Set output[i*N + j] to 1 iff exactly one neighbour contains a 1, otherwise 0.
 * The function is fully parallelised with OpenMP and written to optimise cache
 * locality and branch‑prediction.
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     std::size_t N)
{
    // Ensure the output buffer has the correct size
    output.resize(N * N);

    // Parallel loop over the two dimensions; collapse for better load‑balancing.
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t iN    = i * N;          // offset of the current row
        const bool   top_exist  = (i > 0);
        const bool   bottom_exist = (i < N - 1);
        for (std::size_t j = 0; j < N; ++j) {
            // Fast integer counting of neighbours
            int count = 0;
            if (top_exist      && input[(i-1)*N + j]   == 1) ++count;
            if (bottom_exist   && input[(i+1)*N + j]   == 1) ++count;
            if (j > 0          && input[iN + j - 1]    == 1) ++count;
            if (j < N - 1      && input[iN + j + 1]    == 1) ++count;
            output[iN + j] = (count == 1) ? 1 : 0;
        }
    }
}
