#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Multiplies A(M×K) by B(K×N) and adds the result to C(M×N).
 * All matrices are stored in row-major order.
 *
 * The algorithm uses loop tiling for better cache locality and parallelizes
 * the outer two loops with OpenMP to exploit the 8 available threads.
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    constexpr size_t BLOCK = 64;               // tile size (tune if needed)

    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK) {
        for (size_t kk = 0; kk < K; kk += BLOCK) {
            for (size_t jj = 0; jj < N; jj += BLOCK) {

                size_t i_max = std::min(ii + BLOCK, M);
                size_t k_max = std::min(kk + BLOCK, K);
                size_t j_max = std::min(jj + BLOCK, N);

                for (size_t i = ii; i < i_max; ++i) {
                    const double* restrict a_row = &A[i * K + kk];
                    double* restrict c_row = &C[i * N + jj];
                    for (size_t k = kk; k < k_max; ++k) {
                        double aik = a_row[k - kk];
                        const double* restrict b_row = &B[k * N + jj];
                        for (size_t j = jj; j < j_max; ++j) {
                            c_row[j - jj] += aik * b_row[j - jj];
                        }
                    }
                }
            }
        }
    }
}
