struct Point {
    double x, y;
};

// Fast distance between two points
inline static double fast_dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

double convexHullPerimeter(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // Local copy for sorting
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), [](const Point& p1, const Point& p2) noexcept {
        return (p1.x < p2.x) || (p1.x == p2.x && p1.y < p2.y);
    });

    // Graham scan (Monotone chain)
    std::vector<Point> hull;
    hull.reserve(2 * n);

    auto cross = [](const Point& a, const Point& b, const Point& c) noexcept {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // lower hull
    for (size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i]) <= 0.0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // upper hull
    size_t lower_size = hull.size();
    for (size_t i = n - 1; i > 0; --i) {
        while (hull.size() > lower_size &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i - 1]) <= 0.0)
            hull.pop_back();
        hull.push_back(pts[i - 1]);
    }

    // Remove duplicate first/last point
    if (!hull.empty())
        hull.pop_back();

    // Compute perimeter
    double perimeter = 0.0;
    for (size_t i = 0; i < hull.size(); ++i) {
        const size_t next = (i + 1) % hull.size();
        perimeter += fast_dist(hull[i], hull[next]);
    }

    return perimeter;
}
