#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>   // size_t

struct Point
{
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Find the convex hull of the points in `points` and store it in `hull`.
 * The algorithm is the classic Andrew monotone chain with O(n log n) sorting.
 */
void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3)
    {
        hull = points;   // trivial hull
        return;
    }

    // Make a copy and sort it lexicographically by (x, y)
    std::vector<Point> sorted(points);
    sorted.reserve(n);
    std::sort(sorted.begin(), sorted.end(), [](const Point& a, const Point& b)
    {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    // Reserve enough space for upper + lower hulls (worst case 2n)
    hull.clear();
    hull.reserve(2 * n);

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0.0)
        {
            hull.pop_back();
        }
        hull.push_back(sorted[i]);
    }

    // Build upper hull
    std::size_t lower_size = hull.size() + 1;   // +1 to skip last point of lower hull
    for (std::size_t i = n - 1; i > 0; --i)
    {
        while (hull.size() >= lower_size &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0.0)
        {
            hull.pop_back();
        }
        hull.push_back(sorted[i - 1]);
    }

    // Remove duplicated last point (first point of lower hull)
    if (!hull.empty())
        hull.pop_back();   // removes the duplicate of the first point
}
