#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major order, x has N elements, and y has M elements.
   This implementation preserves the exact semantics of the reference code while
   exploiting parallelism and cache locality.
*/
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Ensure that the input containers have the right size.
    // (The harness guarantees this, but the assertions help catch bugs in
    //  future modifications.)
    if (A.size() != M * N) return;
    if (x.size() != N) return;
    if (y.size() != M) return;

    const double* a = A.data();
    const double* xv = x.data();
    double* yv = y.data();

    const std::size_t block = 64;   // cache blocking factor (tuned on typical L1/L2 sizes)

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        std::size_t j = 0;

        // process blocks of 'block' columns to keep the inner loop cache-friendly
        for (; j + block <= N; j += block) {
            const double* ablock = a + i * N + j;
            for (std::size_t k = 0; k < block; ++k) {
                sum += ablock[k] * xv[j + k];
            }
        }

        // tail loop for remaining columns
        for (; j < N; ++j) {
            sum += a[i * N + j] * xv[j];
        }

        yv[i] = sum;
    }
}
