    // Ensure output vector has the same size (caller is expected to allocate).
    // This avoids accidental allocations that could hide bugs in the harness.
    ranks_.resize(n);

    // 1) Create an index array 0,1,2,...,n-1
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // 2) Sort the indices by the corresponding values in `x`
    //    The comparison is intentional: ascending order.
    std::sort(idx.begin(), idx.end(),
              [&x](std::size_t i1, std::size_t i2)
              { return x[i1] < x[i2]; });

    // 3) Invert the permutation: for each element of `idx`, store its position
    for (std::size_t i = 0; i < n; ++i)
        ranks_[idx[i]] = i;
}
