inline void sortIgnoreZero(std::vector<int> &x)
{
    // If the vector is empty or has no non‑zero elements, do nothing.
    if (x.empty()) return;

    // Reserve space once to avoid reallocations during the push_back loop.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // Collect all non‑zero elements.
    // Using a simple range loop is efficient and cache‑friendly.
    for (int val : x) {
        if (val != 0) {
            nonZero.push_back(val);
        }
    }

    // If there is nothing to sort, return immediately.
    if (nonZero.empty()) return;

    // Sort the non‑zero values. std::sort is highly optimized and will
    // automatically use parallel algorithms on some platforms, but
    // under GCC with -O2 it remains fast for 64‑bit integers.
    std::sort(nonZero.begin(), nonZero.end());

    // Write the sorted values back into the original positions.
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            x[i] = nonZero[idx++];
        }
    }
}
