07_fft_fft_conjugate:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstring>
#include <omp.h>

/*
 * Optimised radix‑2 FFT with conjugate post‑processing.
 *   • iterative Cooley‑Tukey (decimation‑in‑time)
 *   • pre‑computed twiddle factors
 *   • cache‑friendly bit‑reversal
 *   • small amount of OpenMP parallelisation
 *
 * The public interface is identical to the original:
 *      void fftConjugate(std::vector<std::complex<double>>& x);
 */
static inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;                          // nothing to do

    /* ---- 1. bit‑reversal with a small lookup table ------------------- */
    const std::size_t bits = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t r = 0, v = i;
        for (std::size_t b = 0; b < bits; ++b) {
            r = (r << 1) | (v & 1);
            v >>= 1;
        }
        rev[i] = r;
    }
    // In‑place bit reversal
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    /* ---- 2. Pre‑compute twiddle factors ------------------------------- */
    std::vector<std::complex<double>> w(N / 2);
    const double two_pi = 2.0 * M_PI;
    for (std::size_t k = 0; k < N / 2; ++k) {
        const double ang = -two_pi * static_cast<double>(k) / static_cast<double>(N);
        w[k] = std::exp(std::complex<double>(0.0, ang));
    }

    /* ---- 3. Iterative radix‑2 FFT (decimation‑in‑time) -------------- */
    std::size_t m = 1;          // size of sub‑transform
    for (std::size_t s = 1; s <= bits; ++s, ++m) {
        const std::size_t m2 = m << 1;              // 2^s
        const std::size_t step = N / m2;          // spacing of twiddle factors

#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m2) {
            std::size_t wk = 0;
            for (std::size_t j = 0; j < m; ++j, ++wk) {
                const std::complex<double> t = w[wk] * x[k + j + m];
                const std::complex<double> u = x[k + j];
                x[k + j]         = u + t;
                x[k + j + m]     = u - t;
            }
        }
    }

    /* ---- 4. Conjugate the result ------------------------------------- */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
