/// Return the index of the value in the vector x that is closest to the math constant PI.
/// Uses M_PI (from <cmath>).  The function preserves the exact behaviour of the original
/// implementation while providing multi‑threaded performance on up to 8 cores.
size_t findClosestToPi(std::vector<double> const& x)
{
    // Guard against an empty vector – undefined in the original code, but
    // returning 0 is harmless and keeps the signature identical.
    if (x.empty())
        return 0;

    const double pi = M_PI;

    // Store minimal difference and the corresponding index.
    // Use double for the difference to avoid recomputation.
    double min_diff = std::abs(x[0] - pi);
    std::size_t best_idx = 0;

    // Parallel we reduce over the index as well; use custom struct to carry both.
    struct Res { double diff; std::size_t idx; };
    Res local{min_diff, best_idx};

    #pragma omp parallel for reduction( \
        /* explicit reduction that uncovers the lowest diff \
           and keeps its index */ \
        max : local)\
    for (std::size_t i = 1; i < x.size(); ++i) {
        double d = std::abs(x[i] - pi);
        if (d < local.diff) {
            local.diff = d;
            local.idx  = i;
        }
    }

    return local.idx;
