#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix in row-major order.
 * `x` is pre‑allocated with space for N elements.
 */
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              size_t N)
{
    // make local copies to avoid modifying the inputs
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    /* Gaussian elimination (row‑wise).        */
    /* The outer loop is serial because each
     * step depends on the previous pivot row.
     * The inner loop over the target rows can
     * be parallelised with OpenMP.            */
    for (size_t i = 0; i < N - 1; ++i)
    {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0)            // singular matrix – keep the original behaviour
            return;

        /* Parallel elimination of rows below the pivot */
#pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j)
        {
            const double factor = A_copy[j * N + i] / pivot;
            // Update the remaining columns in row j
            for (size_t k = i; k < N; ++k)
                A_copy[j * N + k] -= factor * A_copy[i * N + k];

            b_copy[j] -= factor * b_copy[i];
        }
    }

    /* Back substitution – run serially for simplicity and correctness */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += A_copy[i * N + j] * x[j];
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
