#if !defined(M_PI)
#define M_PI 3.141592653589793238462643383279502884L
#endif

// -----------------------------------------------------------------------------
// Helper: Pre‑compute bit‑reversal table for a given N (must be power of two)
// -----------------------------------------------------------------------------
static inline std::vector<uint32_t> bit_reverse_table(size_t N)
{
    std::vector<uint32_t> rev(N);
    uint32_t m = static_cast<uint32_t>(std::log2(N));
    for (uint32_t i = 0; i < static_cast<uint32_t>(N); ++i)
    {
        uint32_t x = i;
        uint32_t r = 0;
        for (uint32_t j = 0; j < m; ++j)
        {
            r = (r << 1) | (x & 1u);
            x >>= 1u;
        }
        rev[i] = r;
    }
    return rev;
}

// -----------------------------------------------------------------------------
// FFT helper (in‑place radix‑2 Cooley–Tukey)
// -----------------------------------------------------------------------------
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    const size_t logN = static_cast<size_t>(std::log2(N));

    /* Pre‑compute twiddle factors for each stage and store them in a flat array
       so that we can access them with a simple index.  This eliminates the
       repeated recomputation of powers of unity inside the inner loop.  */
    std::vector<std::complex<double>> twiddles(N / 2);
    const double theta = -2.0 * M_PI / N;          // sign depends on convention
    for (size_t i = 0; i < N / 2; ++i)
        twiddles[i] = std::exp(std::complex<double>(0.0, theta * static_cast<double>(i)));

    /* Iterative butterfly loops */
    for (size_t s = 1; s <= logN; ++s)
    {
        const size_t m = 1u << s;          // length of sub‑transform
        const size_t halfM = m >> 1;
        const size_t step = N / m;         // offset between sub‑transforms

        for (size_t j = 0; j < halfM; ++j)
        {
            const std::complex<double> w = twiddles[j * step];
            for (size_t k = j; k < N; k += m)
            {
                const std::complex<double> t = w * x[k + halfM];
                x[k + halfM] = x[k] - t;
                x[k] += t;
            }
        }
    }

    /* Bit‑reversal reordering */
    const std::vector<uint32_t> rev = bit_reverse_table(N);
    for (size_t i = 0; i < N; ++i)
    {
        uint32_t j = rev[i];
        if (j > i)
            std::swap(x[i], x[j]);
    }
}

// -----------------------------------------------------------------------------
// Inverse FFT
// -----------------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();

    /* Complex conjugation (in‑place) */
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    /* Forward FFT */
    fft_helper(x);

    /* Second conjugation */
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    /* Normalisation */
    const double invN = 1.0 / static_cast<double>(N);
    for (size_t i = 0; i < N; ++i)
        x[i] *= invN;
}
