#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

//===---------------------------------------------------------------------===
// Fast Game of Life kernel
//===---------------------------------------------------------------------===
// Computes one generation in a NxN grid.  The grid is stored in row-major
// order in the vectors `input` and `output` (size N*N).  The function uses
// OpenMP to parallelise across the rows.  All logic is identical to the
// reference implementation – no semantic changes.
//
//--------------------------------------------------------------------------
// Design notes:
//   1. The neighbourhood sum for a cell is computed by pointer arithmetic
//      – no index bounds branching.  The first and last rows/columns are
//      handled by adding zero values outside the real edges.
//   2. We pre‑compute the base pointers for every row to avoid repeated
//      multiplication by `N`.
//   3. The inner loop is unrolled a little for a small loop‑carried
//      dependency hint to the compiler.
//   4. The output cell is set directly; the ternary branches are collapsed
//      into a compact expression, avoiding many needless assignments.
//
//--------------------------------------------------------------------------
// Usage:
//   std::vector<int> grid(N * N, 0);
//   gameOfLife(grid, next_grid, N);
//
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N) noexcept
{
    const size_t stride = N;
    const int* in  = input.data();
    int*       out = output.data();

    // Pre‑compute row base pointers
    const int* rows[N];
    for (size_t r = 0; r < N; ++r)
        rows[r] = in + r * stride;

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const int* prev = (i ? rows[i-1] : nullptr);
        const int* cur  = rows[i];
        const int* next = (i+1 < N ? rows[i+1] : nullptr);

        // Linear index of the current row
        size_t idx = i * stride;

        for (size_t j = 0; j < N; ++j, ++idx)
        {
            int sum = 0;

            // 4 direct neighbours
            if (prev) sum += prev[j];
            if (next) sum += next[j];
            sum += cur[j-1] * (j>0);
            sum += cur[j+1] * (j+1<N);

            // 4 diagonal neighbours
            if (prev && j>0)   sum += prev[j-1];
            if (prev && j+1<N) sum += prev[j+1];
            if (next && j>0)   sum += next[j-1];
            if (next && j+1<N) sum += next[j+1];

            // Game of Life rules
            int alive = cur[j];
            out[idx] = (alive
                        ? (sum==2 || sum==3)
                        : (sum==3));
        }
    }
}
