#pragma once
#include <vector>
#include <string>
#include <atomic>
#include <omp.h>

struct Book {
    std::string title;
    int pages;
};

/* Return the index of the last Book item in the vector books where Book.pages is less than 100.
   Example:
   input: [{title="Green Eggs and Ham", pages=72}, {title="gulliver's travels", pages=362},
           {title="Stories of Your Life", pages=54}, {title="Hamilton", pages=818}]
   output: 2
*/
size_t findLastShortBook(std::vector<Book> const& books) {
    const size_t n = books.size();
    std::atomic<size_t> last{n}; // default to books.size()

    #pragma omp parallel for
    for (size_t i = 0; i < n; ++i) {
        if (books[i].pages < 100) {
            size_t cur;
            do {
                cur = last.load(std::memory_order_relaxed);
                // only update if we found a later index
            } while (i > cur && !last.compare_exchange_weak(cur, i,
                         std::memory_order_release, std::memory_order_relaxed));
        }
    }
    return last.load(std::memory_order_acquire);
}
