// Edge detection kernel (constant).
static constexpr int edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

/*
 * Convolve a grayscale image with the predefined 3×3 edge kernel.
 * - imageIn   : input image (row‑major, N×N).
 * - imageOut  : output image, must already have N×N elements.
 * - N         : image dimension.
 *
 * Behaviour is identical to the reference implementation.
 * The routine is parallelised with OpenMP and heavily tuned for speed.
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           size_t                 N)
{
    const std::size_t stride = N;
    const std::size_t total   = N * N;

    // Parallelised across all pixels.  The two outer loops are collapsed
    // to give a single parallel region that balances the workload.
#pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t i_n = i * stride;
        for (std::size_t j = 0; j < N; ++j)
        {
            /* -----------------------------------------------------------------
               Perform the 3×3 convolution.  Rather than formulating a generic
               inner loop, each of the nine accesses is written explicitly; this
               allows the compiler to remove bounds checks and to optimise the
               memory traffic.  Border pixels are handled by simple conditional
               checks; in the extreme case where the kernel accesses outside the
               image the contribution is zero, which is implicitly satisfied by
               skipping those indices.
            ----------------------------------------------------------------- */
            int sum = 0;

            // Row i-1
            if (i > 0) {
                const std::size_t idx = (i - 1) * stride;
                if (j > 0)   sum += imageIn[idx + j - 1] * edgeKernel[0][0];
                sum += imageIn[idx + j    ] * edgeKernel[0][1];
                if (j + 1 < N) sum += imageIn[idx + j + 1] * edgeKernel[0][2];
            }

            // Row i
            {
                const std::size_t idx = i_n;
                if (j > 0)   sum += imageIn[idx + j - 1] * edgeKernel[1][0];
                sum += imageIn[idx + j    ] * edgeKernel[1][1];
                if (j + 1 < N) sum += imageIn[idx + j + 1] * edgeKernel[1][2];
            }

            // Row i+1
            if (i + 1 < N) {
                const std::size_t idx = (i + 1) * stride;
                if (j > 0)   sum += imageIn[idx + j - 1] * edgeKernel[2][0];
                sum += imageIn[idx + j    ] * edgeKernel[2][1];
                if (j + 1 < N) sum += imageIn[idx + j + 1] * edgeKernel[2][2];
            }

            /* -----------------------------------------------------------------
               Clip the convolved value to the valid byte range [0, 255] and
               store it in the output buffer.
            ----------------------------------------------------------------- */
            imageOut[i_n + j] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
}
