#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Computes one iteration of a 5‑point 2‑D Jacobi stencil.
 *
 *   output[i,j] = (input[i,j]
 *                 + input[i-1,j] + input[i+1,j]
 *                 + input[i,j-1] + input[i,j+1]) / 5.0
 *
 * Padding outside the grid is assumed to be zero.
 *
 * The implementation:
 *   * Splits work only over the interior cells (1..N-2) to avoid
 *     branching in the inner loop.
 *   * Handles the four boundary lines separately.
 *   * Uses OpenMP parallel for with static scheduling.
 *   * Uses raw pointer arithmetic for maximum spatial locality.
 *   * Keeps the original function signature unchanged.
 */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double> &output,
                     std::size_t N)
{
    if (N == 0) return;

    const double inv5 = 0.2;          // 1.0/5.0
    const double* in = input.data();
    double* out = output.data();
    const std::size_t stride = N;

    /* --- interior cells (i=1..N-2, j=1..N-2) --- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i < N-1; ++i) {
        const double* row_off  = in + i * stride;
        double*       row_out = out + i * stride;
        const double* up       = in + (i-1) * stride;
        const double* down     = in + (i+1) * stride;
        for (std::size_t j = 1; j < N-1; ++j) {
            double sum = row_off[j]
                        + up[j]
                        + down[j]
                        + row_off[j-1]
                        + row_off[j+1];
            row_out[j] = sum * inv5;
        }
    }

    /* --- top and bottom rows (i=0 and i=N-1) --- */
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        /* top row i=0 */
        double sum_top = in[j]
                       + ((j>0)  ? in[j-1] : 0.0)
                       + ((j+1<N) ? in[j+1] : 0.0)
                       + ((N>1) ? in[1*N + j] : 0.0);   /* i+1 */
        out[j] = sum_top * inv5;

        /* bottom row i=N-1 */
        if (N > 1) {
            std::size_t i = N-1;
            double sum_bot = in[i*stride + j]
                          + ((j>0)  ? in[i*stride + j-1] : 0.0)
                          + ((j+1<N) ? in[i*stride + j+1] : 0.0)
                          + ((i>0) ? in[(i-1)*stride + j] : 0.0); /* i-1 */
            out[i*stride + j] = sum_bot * inv5;
        }
    }

    /* --- left and right columns (j=0 and j=N-1) for inner rows --- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i < N-1; ++i) {
        std::size_t base = i * stride;
        /* left column j=0 */
        double sum_left = in[base]
                       + ((i>0)  ? in[(i-1)*stride] : 0.0)
                       + ((i+1<N) ? in[(i+1)*stride] : 0.0)
                       + ((N>1) ? in[base + 1] : 0.0);  /* j+1 */
        out[base] = sum_left * inv5;

        /* right column j=N-1 */
        std::size_t j = N-1;
        double sum_right = in[base + j]
                          + ((i>0)  ? in[(i-1)*stride + j] : 0.0)
                          + ((i+1<N) ? in[(i+1)*stride + j] : 0.0)
                          + ((j>0) ? in[base + j-1] : 0.0);
        out[base + j] = sum_right * inv5;
    }
}
